/**
 * Single source of truth for the Setaweet Archive.
 *
 * Text (title, year, description, links) lives here; the image / audio / video
 * / pdf file paths come from src/content/archive-media.json, generated by the
 * asset-import script from the real folders under src/assets and copied into
 * /public/archive/<slug>/.
 */

import mediaManifest from "@/content/archive-media.json";

export type ArchiveImage = {
  /** Path under /public, e.g. "/archive/alegnta/hero.jpg". Optional = placeholder. */
  src?: string;
  alt: string;
};

/** A named campaign/effort that lives inside a parent project's page. */
export type SubProject = {
  slug: string;
  title: string;
  /** Paragraphs separated by a blank line. */
  description: string;
  cover: ArchiveImage;
  images: ArchiveImage[];
  video?: string;
  audio?: string;
  pdf?: string;
  links?: string[];
};

export type Project = {
  slug: string;
  title: string;
  year: number;
  /** Paragraphs separated by a blank line. */
  description: string;
  /** Main image used on the home archive carousel. */
  cover: ArchiveImage;
  /** Gallery images shown on the project page. */
  images: ArchiveImage[];
  /** Optional embedded media found in the project folder. */
  video?: string;
  audio?: string;
  pdf?: string;
  /** External links (e.g. YouTube). */
  links?: string[];
  website?: string;
  /** Sub-projects rendered as their own sections on the project page. */
  subProjects?: SubProject[];
};

type MediaEntry = {
  cover: string | null;
  images: string[];
  video?: string;
  audio?: string;
  pdf?: string;
  subProjects?: Record<string, Omit<MediaEntry, "subProjects">>;
};

const media = mediaManifest as Record<string, MediaEntry>;

type SubProjectMeta = {
  slug: string;
  title: string;
  description: string;
  links?: string[];
};

type ProjectMeta = {
  slug: string;
  title: string;
  year: number;
  description: string;
  links?: string[];
  website?: string;
  subProjects?: SubProjectMeta[];
};

