export const projects: Project[] = META.map((m) => {
  const assets = media[m.slug] ?? { cover: null, images: [] };
  return {
    slug: m.slug,
    title: m.title,
    year: m.year,
    description: m.description,
    links: m.links,
    website: m.website,
    cover: { src: assets.cover ?? undefined, alt: `${m.title} cover` },
    images: assets.images.map((src, i) => ({ src, alt: `${m.title} image ${i + 1}` })),
    video: assets.video,
    audio: assets.audio,
    pdf: assets.pdf,
    subProjects: m.subProjects?.map((s) => {
      const sub = assets.subProjects?.[s.slug] ?? { cover: null, images: [] };
      return {
        slug: s.slug,
        title: s.title,
        description: s.description,
        links: s.links,
        cover: { src: sub.cover ?? undefined, alt: `${s.title} cover` },
        images: sub.images.map((src, i) => ({ src, alt: `${s.title} image ${i + 1}` })),
        video: sub.video,
        audio: sub.audio,
        pdf: sub.pdf,
      };
    }),
  };
});

export const projectsBySlug: Record<string, Project> = Object.fromEntries(
  projects.map((p) => [p.slug, p])
);

/** Ascending list of distinct years present in the archive. */
export const archiveYears: number[] = Array.from(new Set(projects.map((p) => p.year))).sort(
  (a, b) => a - b
);
